function fmt(d) { if (!d) return "\u2014"; var dt = new Date(d + "T00:00:00"); return dt.toLocaleDateString("en-GB", { day: "2-digit", month: "short", year: "numeric" }); }
function money(v, c) { return (CUR[c] || "") + v.toLocaleString("en-GB", { minimumFractionDigits: 2, maximumFractionDigits: 2 }); }
function r6(v) { return Math.round(v * 1000000) / 1000000; }
function r2(v) { return Math.round(v * 100) / 100; }
function addDays(s, n) { var p = s.split("-"); var d = new Date(Date.UTC(parseInt(p[0]), parseInt(p[1]) - 1, parseInt(p[2]))); d.setUTCDate(d.getUTCDate() + n); return d.toISOString().split("T")[0]; }
function daysBetween(a, b) { var pa = a.split("-"); var pb = b.split("-"); return Math.round((Date.UTC(parseInt(pb[0]), parseInt(pb[1]) - 1, parseInt(pb[2])) - Date.UTC(parseInt(pa[0]), parseInt(pa[1]) - 1, parseInt(pa[2]))) / 86400000); }
function makeRng(seed) { var s = seed; return function() { s = (s * 16807) % 2147483647; return (s - 1) / 2147483646; }; }

// ======== Tranche helpers ========
// A "tranche" represents a discrete capital advance event on an invoice.
// The full set of tranches is the source of truth for interest/capital math.

// Synthesize a tranche from legacy invoice fields when tranches is empty/missing.
// Idempotent — safe to call repeatedly. Returns a new array; does not mutate input.
function synthesizeTranches(inv) {
  if (Array.isArray(inv.tranches) && inv.tranches.length > 0) return inv.tranches;
  if (!inv.fundedDate || !(inv.capitalDue > 0)) return [];
  var term = daysBetween(inv.fundedDate, inv.dueDate);
  if (term < 1) term = 1;
  return [{
    trancheId: "T1",
    capital: r2(inv.capitalDue),
    capitalRepaid: 0,
    rate: inv.annualRate || 0,
    advancedDate: inv.fundedDate,
    term: term,
    status: "active"
  }];
}

// Sum the active capital across all tranches — i.e. capital that has been
// advanced but not yet repaid. Equivalent to invoice.capitalDue under the
// new model.
function tranchesActiveCapital(tranches) {
  if (!Array.isArray(tranches)) return 0;
  return r2(tranches.reduce(function(s, t) { return s + Math.max(0, (t.capital || 0) - (t.capitalRepaid || 0)); }, 0));
}

// Compute total interest charged across active tranches. Each tranche
// contributes: outstanding_capital * (rate / 360) * term_days.
function tranchesInterestCharged(tranches) {
  if (!Array.isArray(tranches)) return 0;
  return r2(tranches.reduce(function(s, t) {
    var outstanding = Math.max(0, (t.capital || 0) - (t.capitalRepaid || 0));
    if (outstanding <= 0) return s;
    return s + outstanding * ((t.rate || 0) / 360) * (t.term || 0);
  }, 0));
}

// Weighted-average rate across active tranches, by capital outstanding.
// Used for display purposes only.
function tranchesWeightedRate(tranches) {
  if (!Array.isArray(tranches) || tranches.length === 0) return 0;
  var num = 0, den = 0;
  tranches.forEach(function(t) {
    var outstanding = Math.max(0, (t.capital || 0) - (t.capitalRepaid || 0));
    if (outstanding <= 0) return;
    num += outstanding * (t.rate || 0);
    den += outstanding;
  });
  return den > 0 ? num / den : 0;
}

// Apply a capital repayment FIFO across tranches.
// Mutates tranches array. Returns { applied, remaining }.
// Older tranches (earlier advancedDate) get paid back first.
function applyCapitalRepaymentFIFO(tranches, amount) {
  if (!Array.isArray(tranches) || amount <= 0) return { applied: 0, remaining: amount || 0 };
  // Sort by advancedDate ascending — oldest first
  var ordered = tranches.slice().sort(function(a, b) {
    return (a.advancedDate || "") < (b.advancedDate || "") ? -1 : 1;
  });
  var remaining = amount;
  var applied = 0;
  for (var i = 0; i < ordered.length && remaining > 0.005; i++) {
    var t = ordered[i];
    var outstanding = Math.max(0, (t.capital || 0) - (t.capitalRepaid || 0));
    if (outstanding <= 0.005) continue;
    var take = Math.min(remaining, outstanding);
    t.capitalRepaid = r2((t.capitalRepaid || 0) + take);
    remaining -= take;
    applied += take;
    if (Math.abs((t.capital || 0) - t.capitalRepaid) < 0.005) t.status = "fully_repaid";
    else t.status = "partially_repaid";
  }
  return { applied: r2(applied), remaining: r2(remaining) };
}

// ======== Entity ID helpers ========
// Entity ID format: "SUP-001" (parent) or "SUP-001:BR-001" (branch)
function parseEntityId(entityId) {
  if (!entityId) return { supplierId: null, branchId: null };
  var parts = entityId.split(":");
  return { supplierId: parts[0], branchId: parts[1] || null };
}
function makeEntityId(supplierId, branchId) {
  return branchId ? supplierId + ":" + branchId : supplierId;
}

// --- Registry-ID dedup helpers (stage 1.7) ---------------------------------
// Normalise a CH number for comparison: trim, uppercase, left-pad to 8.
function normCoNum(n) {
  if (!n) return "";
  return String(n).trim().toUpperCase().replace(/\s+/g, "").padStart(8, "0");
}
// Normalise a legal name for mismatch comparison. Operators type "Tesco" where
// CH holds "TESCO STORES LIMITED"; a raw !== would warn on nearly every manual
// entry and train people to click through. Strip common suffixes/punctuation
// and collapse whitespace so only a MATERIAL difference trips the warning.
function normLegalName(s) {
  if (!s) return "";
  return String(s)
    .toUpperCase()
    .replace(/[.,()]/g, " ")
    .replace(/\b(LIMITED|LTD|PLC|LLP|L\.L\.P|CO|COMPANY|THE|AND|&)\b/g, " ")
    .replace(/[^A-Z0-9]/g, " ")
    .replace(/\s+/g, " ")
    .trim();
}
// Find an existing parent entity in the given DB sharing the same
// (verification_source, company_number). Returns the entity or null.
// Branches never have their own rows, so this only ever matches a parent.
function findRegistryClash(db, source, coNum, excludeId) {
  var n = normCoNum(coNum);
  if (!n) return null;
  var src = source || "companies_house";
  return db.find(function(e) {
    if (excludeId && e.id === excludeId) return false;
    if (!e.companyNumber) return false;
    return normCoNum(e.companyNumber) === n &&
      (e.verificationSource || "companies_house") === src;
  }) || null;
}
// ---------------------------------------------------------------------------

function getSupplierById(entityId) {
  if (!entityId) return null;
  var parsed = parseEntityId(entityId);
  return SUPPLIERS_DB.find(function(s) { return s.id === parsed.supplierId; }) || null;
}
function getBranchById(entityId) {
  if (!entityId) return null;
  var parsed = parseEntityId(entityId);
  if (!parsed.branchId) return null;
  var sup = SUPPLIERS_DB.find(function(s) { return s.id === parsed.supplierId; });
  if (!sup || !sup.branches) return null;
  return sup.branches.find(function(b) { return b.branchId === parsed.branchId; }) || null;
}
function getParentEntityId(entityId) {
  if (!entityId) return entityId;
  return parseEntityId(entityId).supplierId;
}
function getEntityDisplayName(entityId) {
  if (!entityId) return "";
  var sup = getSupplierById(entityId);
  if (!sup) return entityId;
  var br = getBranchById(entityId);
  return br ? sup.name + " \u2014 " + br.branchName : sup.name;
}
// Build a list of all supplier entities for dropdowns: [{ value: "SUP-001", label: "Parent" }, { value: "SUP-001:BR-001", label: "Parent — Branch" }]
function getAllSupplierEntities() {
  var result = [];
  SUPPLIERS_DB.forEach(function(s) {
    result.push({ value: s.id, label: s.name, supplierId: s.id, isBranch: false });
    if (s.branches) s.branches.forEach(function(br) {
      var eid = makeEntityId(s.id, br.branchId);
      result.push({ value: eid, label: s.name + " \u2014 " + br.branchName, supplierId: s.id, isBranch: true, branchId: br.branchId || "" });
    });
  });
  return result;
}
// Backward-compat: name-based helpers (used during migration, eventually removable)
function getParentSupplierName(nameOrId) {
  if (!nameOrId) return nameOrId;
  // If it looks like an ID (SUP-xxx or SUP-xxx:BR-xxx), resolve to name
  if (nameOrId.match && nameOrId.match(/^SUP-/)) {
    var sup = getSupplierById(nameOrId);
    return sup ? sup.name : nameOrId;
  }
  var sep = nameOrId.indexOf(" \u2014 ");
  return sep >= 0 ? nameOrId.substring(0, sep) : nameOrId;
}
function getBranchName(nameOrId) {
  if (!nameOrId) return null;
  if (nameOrId.match && nameOrId.match(/^SUP-/)) {
    var br = getBranchById(nameOrId);
    return br ? br.branchName : null;
  }
  var sep = nameOrId.indexOf(" \u2014 ");
  return sep >= 0 ? nameOrId.substring(sep + 3) : null;
}
function getParentSupplier(nameOrId) {
  if (!nameOrId) return null;
  if (nameOrId.match && nameOrId.match(/^SUP-/)) return getSupplierById(nameOrId);
  var pn = getParentSupplierName(nameOrId);
  return SUPPLIERS_DB.find(function(s) { return s.name === pn; }) || null;
}
function isSameParentSupplier(id1, id2) {
  return getParentEntityId(id1) === getParentEntityId(id2);
}
// Resolve a supplierId to display name (used in tables etc)
function supName(entityId) { return getEntityDisplayName(entityId); }

// ======== Buyer-side entity helpers ========
// Mirror of the supplier-side family above. Composite ID syntax is identical
// ("BUY-001" or "BUY-001:BR-001"); parseEntityId / makeEntityId are reused
// since they're prefix-agnostic. The .supplierId field returned from
// parseEntityId is misnamed — it just holds "the parent part" regardless of
// whether the entity is a supplier or a buyer. Don't be misled by the name.
function getBuyerById(entityId) {
  if (!entityId) return null;
  var parsed = parseEntityId(entityId);
  return BUYERS_DB.find(function(b) { return b.id === parsed.supplierId; }) || null;
}
function getBuyerBranchById(entityId) {
  if (!entityId) return null;
  var parsed = parseEntityId(entityId);
  if (!parsed.branchId) return null;
  var buy = BUYERS_DB.find(function(b) { return b.id === parsed.supplierId; });
  if (!buy || !buy.branches) return null;
  return buy.branches.find(function(b) { return b.branchId === parsed.branchId; }) || null;
}
function getBuyerEntityDisplayName(entityId) {
  if (!entityId) return "";
  var buy = getBuyerById(entityId);
  if (!buy) return entityId;
  var br = getBuyerBranchById(entityId);
  return br ? buy.name + " \u2014 " + br.branchName : buy.name;
}
function getAllBuyerEntities() {
  var result = [];
  BUYERS_DB.forEach(function(b) {
    result.push({ value: b.id, label: b.name, buyerId: b.id, isBranch: false });
    if (b.branches) b.branches.forEach(function(br) {
      var eid = makeEntityId(b.id, br.branchId);
      result.push({ value: eid, label: b.name + " \u2014 " + br.branchName, buyerId: b.id, isBranch: true, branchId: br.branchId || "" });
    });
  });
  return result;
}
// Backward-compatible flat-buyer name helper. Now branch-aware: given a
// composite entity ID it returns "Parent — Branch"; given a flat parent ID
// it returns just the parent name. Callers that pass a plain "BUY-001" keep
// working unchanged.
function buyName(buyerEntityId) {
  if (!buyerEntityId) return "";
  // If it looks like a composite or known buyer ID, route through the new helper
  if (buyerEntityId.match && buyerEntityId.match(/^BUY-/)) {
    return getBuyerEntityDisplayName(buyerEntityId);
  }
  // Fallback: treat as flat parent ID (legacy callers)
  var b = BUYERS_DB.find(function(x) { return x.id === buyerEntityId; });
  return b ? b.name : buyerEntityId;
}

// Check if a supplier entity (parent or branch) is paused.
//
// Pause semantics (two layers):
//   1. Global pause — supplier.paused or branch.paused — affects ALL programs
//      for this entity. Set via the supplier header pause/unpause button.
//   2. Per-program pause — supplier.programPaused[programId] or
//      branch.programPaused[programId] — affects only that one program.
//      Set via the Rates & Current Balances panel.
//
// programId is optional. If omitted, only the global pause is checked
// (preserving legacy behaviour for sites that don't care which program).
// When passed, the function returns true if EITHER the global OR the
// per-program pause is set.
//
// Branch pauses inherit the same two-layer model: if the branch has a
// program-specific pause for this program, that branch is paused on that
// program even if the parent isn't.
function isEntityPaused(entityId, programId) {
  if (!entityId) return false;
  var sup = getSupplierById(entityId);
  if (!sup) return false;
  // Layer 1: parent global pause
  if (sup.paused) return true;
  // Layer 1: branch global pause
  var branch = getBranchById(entityId);
  if (branch && branch.paused) return true;
  // Layer 2: per-program pauses (only when programId provided)
  if (programId) {
    if (sup.programPaused && sup.programPaused[programId]) return true;
    if (branch && branch.programPaused && branch.programPaused[programId]) return true;
  }
  return false;
}

// Buyer-side mirror of isEntityPaused. Same two-layer model.
// Today most callers pass inv.buyerId (the parent), so branch-level
// pauses are a no-op for that path; once callers pass buyerEntityId the
// branch-pause check becomes effective. Per-program pause works at both
// parent and branch level.
function isBuyerPaused(buyerEntityId, programId) {
  if (!buyerEntityId) return false;
  var b = getBuyerById(buyerEntityId);
  if (!b) return false;
  if (b.paused) return true;
  var branch = getBuyerBranchById(buyerEntityId);
  if (branch && branch.paused) return true;
  if (programId) {
    if (b.programPaused && b.programPaused[programId]) return true;
    if (branch && branch.programPaused && branch.programPaused[programId]) return true;
  }
  return false;
}

// ======== Cascade-aware limit helpers (module scope, pure) ========
// These are pure functions: they read SUPPLIERS_DB / BUYERS_DB and the
// invoice's own fields, nothing component-scoped. Module scope lets
// non-component sites (e.g. getEligiblePrograms) use them.
// The exposure-summing primitives, which need viewData.invoices, stay
// inside the component — see getSupplierProgramExposureScoped et al.
function _invSupplierBranchOf(inv) {
  // Decode an invoice's supplier branch from whatever fields it carries.
  // Importer-created invoices: inv.supplierBranchId directly.
  // Stage-3 invoices: inv.supplierEntityId is composite ("SUP-001:BR-002").
  // Legacy: composite stored in inv.supplierId itself.
  if (!inv) return null;
  if (inv.supplierBranchId) return inv.supplierBranchId;
  var ent = inv.supplierEntityId || inv.supplierId;
  if (!ent) return null;
  var br = parseEntityId(ent).branchId;
  return br || null;
}
function _invBuyerBranchOf(inv) {
  if (!inv) return null;
  if (inv.buyerBranchId) return inv.buyerBranchId;
  var ent = inv.buyerEntityId || inv.buyerId;
  if (!ent) return null;
  var br = parseEntityId(ent).branchId;
  return br || null;
}

// Return an invoice's supplier as a composite entity ID, suitable for
// passing to getSupplierBankDetails / getEntityDisplayName / supplier lookups.
// Preference order: pre-built composite, then assemble from parent + branch,
// then bare parent. Returns "" if nothing resolvable.
function _invSupplierEntityIdOf(inv) {
  if (!inv) return "";
  if (inv.supplierEntityId) return inv.supplierEntityId;
  if (inv.supplierId && inv.supplierBranchId) return makeEntityId(inv.supplierId, inv.supplierBranchId);
  return inv.supplierId || "";
}
function _invBuyerEntityIdOf(inv) {
  if (!inv) return "";
  if (inv.buyerEntityId) return inv.buyerEntityId;
  if (inv.buyerId && inv.buyerBranchId) return makeEntityId(inv.buyerId, inv.buyerBranchId);
  return inv.buyerId || "";
}

// Check whether an invoice's amount fits under the cascading single-invoice
// limit (parent's cap AND, if applicable, branch's cap). Returns null if
// the invoice clears, or a string reason if it doesn't.
function checkSupplierProgramCascadingSingleInvoiceLimit(inv, programId) {
  if (!inv || !programId) return null;
  var entityId = inv.supplierEntityId || inv.supplierId;
  if (!entityId) return null;
  var parentId = parseEntityId(entityId).supplierId || entityId;
  var branchId = _invSupplierBranchOf(inv);
  var sup = SUPPLIERS_DB.find(function(s) { return s.id === parentId; });
  if (!sup) return null;
  var amt = inv.amount || 0;
  var parentSIL = (sup.singleInvoiceLimits || {})[programId];
  if (parentSIL && parentSIL > 0 && amt > parentSIL) {
    return "Invoice exceeds supplier's single-invoice limit (" + money(parentSIL, inv.currency) + ")";
  }
  if (branchId) {
    var branch = (sup.branches || []).find(function(b) { return b.branchId === branchId; });
    if (branch) {
      var branchSIL = (branch.singleInvoiceLimits || {})[programId];
      if (branchSIL && branchSIL > 0 && amt > branchSIL) {
        return "Invoice exceeds branch's single-invoice limit (" + money(branchSIL, inv.currency) + ")";
      }
    }
  }
  return null;
}

function checkBuyerProgramCascadingSingleInvoiceLimit(inv, programId) {
  if (!inv || !programId) return null;
  var entityId = inv.buyerEntityId || inv.buyerId;
  if (!entityId) return null;
  var parentId = parseEntityId(entityId).supplierId || entityId;
  var branchId = _invBuyerBranchOf(inv);
  var buy = BUYERS_DB.find(function(b) { return b.id === parentId; });
  if (!buy) return null;
  var amt = inv.amount || 0;
  var parentSIL = (buy.singleInvoiceLimits || {})[programId];
  if (parentSIL && parentSIL > 0 && amt > parentSIL) {
    return "Invoice exceeds buyer's single-invoice limit (" + money(parentSIL, inv.currency) + ")";
  }
  if (branchId) {
    var branch = (buy.branches || []).find(function(b) { return b.branchId === branchId; });
    if (branch) {
      var branchSIL = (branch.singleInvoiceLimits || {})[programId];
      if (branchSIL && branchSIL > 0 && amt > branchSIL) {
        return "Invoice exceeds buyer branch's single-invoice limit (" + money(branchSIL, inv.currency) + ")";
      }
    }
  }
  return null;
}

// Determines whether Pelagic has economic exposure to an invoice. Used as
// the single source of truth for splitting payment/CN allocation flows
// between funded-recovery (Pelagic recovers capital/interest) and
// pass-through (collection agent for the supplier, no Pelagic exposure).
//
// An invoice is "funded" iff Pelagic has actually advanced capital against
// it — either capitalDue is positive (capital still outstanding) OR
// fundedDate is set (indicating capital was advanced at some point even
// if now fully repaid). This bypasses the lifecycle-status string entirely
// and gets the economics right for transitional states like
// purchased-but-not-yet-funded (which is economically a pass-through).
function isFundedInvoice(inv) {
  if (!inv) return false;
  if ((inv.capitalDue || 0) > 0.01) return true;
  if (inv.fundedDate) return true;
  return false;
}

// Returns true if the given entity has KYC marked passed. Null-safe across
// entity shapes. Suppliers and buyers gate unpause on this; service providers
// carry the same field but don't gate. Branch entities don't have their own
// KYC — they inherit the parent supplier's KYC state.
function kycIsPassed(entity) {
  if (!entity) return false;
  return !!(entity.kyc && entity.kyc.passed);
}

// Inspects the audit log to determine *why* and *when* the entity was most
// recently paused, and by whom. Used by the entity-detail Pause banner to
// give operators a clear "why is this paused?" answer without making them
// dig through the audit tab themselves.
//
// Returns { pausedAt, pausedBy, source, context } when paused, or null when
// the audit trail shows the entity is currently unpaused (or no pause events
// exist). source is one of:
//   "auto_program_add" — last pause came from first-program addition
//                        (Supplier/Buyer Added to Program with forcePaused).
//   "manual"           — last pause came from the Pause toggle.
//   "unknown"          — entity.paused is true but no matching audit entry
//                        was found (legacy data, or audit not yet hydrated).
function getPauseContext(entityId) {
  if (!entityId) return null;
  // Walk audit entries newest-first. Stop on first event that touches pause
  // state for this entity — its kind determines our answer.
  for (var i = AUDIT_LOG.length - 1; i >= 0; i--) {
    var e = AUDIT_LOG[i];
    var ctx = e.context || {};
    if (ctx.entityId !== entityId && ctx.supplierId !== entityId && ctx.buyerId !== entityId) continue;
    if (e.action === "Entity Unpaused") return null;
    if (e.action === "Entity Paused") {
      return {
        pausedAt: e.timestamp,
        pausedDisplay: e.displayTime,
        pausedBy: ctx.userEmail || ctx.userName || "unknown user",
        source: "manual",
        context: ctx
      };
    }
    if ((e.action === "Supplier Added to Program" || e.action === "Buyer Added to Program") && ctx.forcePaused === true) {
      return {
        pausedAt: e.timestamp,
        pausedDisplay: e.displayTime,
        pausedBy: ctx.userEmail || ctx.userName || "unknown user",
        source: "auto_program_add",
        context: ctx
      };
    }
  }
  return null;
}

// ======== Entity files (Supabase Storage) ========
// Files for suppliers/buyers/service_providers live in the entity-files
// bucket (private, signed URLs only). Each entity row stores metadata
// only — fileName, label, notes, storagePath, uploadedAt, size, uploadedBy.
// The storagePath is the bucket-relative path; we hand it to signed-URL
// generation when the user wants to download.

var ENTITY_FILES_BUCKET = "entity-files";
var ENTITY_FILES_MAX_BYTES = 10 * 1024 * 1024; // 10 MB per file

// Sanitise a filename for use in a storage path. Strips characters that
// confuse signed-URL generation or the Storage API (slashes, control
// chars, leading dots) and trims to a sensible length. Preserves the
// extension where possible.
function sanitiseFileName(name) {
  if (!name) return "file";
  // Strip path separators, control chars, and other weirdness.
  var cleaned = String(name).replace(/[\\/\x00-\x1f\x7f]/g, "_").replace(/^\.+/, "");
  // Collapse runs of whitespace; replace spaces with underscores for URL friendliness.
  cleaned = cleaned.replace(/\s+/g, "_");
  // Cap length so the full path stays comfortably under any backend limit.
  if (cleaned.length > 120) {
    var dot = cleaned.lastIndexOf(".");
    if (dot > 0 && dot > cleaned.length - 12) {
      var ext = cleaned.slice(dot);
      cleaned = cleaned.slice(0, 120 - ext.length) + ext;
    } else {
      cleaned = cleaned.slice(0, 120);
    }
  }
  return cleaned || "file";
}

// Build the storage path for a new entity file. The UUID prefix prevents
// collisions when the same filename gets uploaded twice. Path shape:
//   {entity_type}/{entity_id}/{uuid}-{filename}
function makeEntityFilePath(entityType, entityId, fileName) {
  // Tiny v4-ish UUID; not crypto-grade, just unique enough for filename collisions
  var uid = "xxxxxxxx-xxxx".replace(/[x]/g, function() { return ((Math.random() * 16) | 0).toString(16); });
  return entityType + "/" + entityId + "/" + uid + "-" + sanitiseFileName(fileName);
}

// Upload a file to the entity-files bucket. Returns a promise that
// resolves to the storage path on success or rejects with a clear error.
async function uploadEntityFile(entityType, entityId, file) {
  if (!file) throw new Error("No file provided");
  if (file.size > ENTITY_FILES_MAX_BYTES) {
    throw new Error("File exceeds " + Math.floor(ENTITY_FILES_MAX_BYTES / (1024 * 1024)) + " MB limit");
  }
  var path = makeEntityFilePath(entityType, entityId, file.name);
  var res = await supabase.storage.from(ENTITY_FILES_BUCKET).upload(path, file, {
    cacheControl: "3600",
    upsert: false,
    contentType: file.type || "application/octet-stream"
  });
  if (res.error) throw new Error(res.error.message || "Upload failed");
  return path;
}

// Generate a short-lived signed URL for downloading a stored file. Default
// expiry 60 minutes — long enough to click-and-fetch but not lingering.
async function getEntityFileSignedUrl(storagePath, expirySeconds) {
  if (!storagePath) throw new Error("No storage path");
  var ttl = expirySeconds || 3600;
  var res = await supabase.storage.from(ENTITY_FILES_BUCKET).createSignedUrl(storagePath, ttl);
  if (res.error) throw new Error(res.error.message || "Could not generate download link");
  return res.data.signedUrl;
}

// Delete a stored file. Idempotent — non-existent paths return success.
async function deleteEntityFile(storagePath) {
  if (!storagePath) return;
  var res = await supabase.storage.from(ENTITY_FILES_BUCKET).remove([storagePath]);
  if (res.error) {
    // Don't throw — caller still wants to remove the metadata row even
    // if the storage object is already gone (manual cleanup, retention
    // expiry, etc.). Just log so it shows up in console.
    console.warn("[deleteEntityFile] Storage delete failed:", res.error.message, "path:", storagePath);
  }
}

// ======== Schema mapping helpers (Stage 3) ========
// All Supabase rows use ID-based columns: supplier_id (parent only), supplier_entity_id
// (parent or composite "SUP-001:BR-001"). supplier_name / buyer_name no longer exist.
// In-memory keeps supplierName / buyerName as denormalised display fields, populated
// from SUPPLIERS_DB / BUYERS_DB at load time.

// Resolve a (parent supplier ID, entity ID) tuple from a supplier_id-shaped value
// that might be either a parent ID or a composite. Returns { supplierId, entityId }.
function resolveSupplierIds(rowSupplierId, rowSupplierEntityId) {
  // Prefer the explicit entity_id column when present; fall back to supplier_id when
  // the entity column is missing (legacy data, optional columns).
  var entityId = rowSupplierEntityId || rowSupplierId || "";
  var parentId = parseEntityId(entityId).supplierId || entityId || "";
  return { supplierId: parentId, entityId: entityId };
}
function resolveBuyerIds(rowBuyerId, rowBuyerEntityId) {
  var entityId = rowBuyerEntityId || rowBuyerId || "";
  var parentId = entityId.indexOf(":") > -1 ? entityId.split(":")[0] : (entityId || "");
  return { buyerId: parentId, entityId: entityId };
}

// Format an audit log timestamp for display, mirroring the formatter used by
// _auditLog at write time. If the row's context carries an asOfDate (entries
// recorded under a scrubbed As-Of date), the display uses that instead, with
// a " (as of)" suffix — preserving the legacy displayTime semantics.
function formatAuditDisplayTime(createdAt, ctx) {
  ctx = ctx || {};
  if (ctx.asOfDate) {
    var asOf = new Date(ctx.asOfDate + "T12:00:00");
    return asOf.toLocaleString("en-GB", {
      day: "2-digit", month: "short", year: "numeric",
      hour: "2-digit", minute: "2-digit", second: "2-digit", hour12: false
    }) + " (as of)";
  }
  if (!createdAt) return "";
  var d = new Date(createdAt);
  return d.toLocaleString("en-GB", {
    day: "2-digit", month: "short", year: "numeric",
    hour: "2-digit", minute: "2-digit", second: "2-digit", hour12: false
  });
}

// Build an audit_log INSERT row from an in-memory entry. Pulls explicit ID columns
// out of the JSONB context so RLS can match them directly. The DB fills created_at
// itself (DEFAULT now()), so we only override it for As-Of entries that need to
// carry their original recording moment if present.
function auditEntryToDbRow(entry) {
  var ctx = entry.context || {};
  var row = {
    event_type: entry.action,
    details: entry.details,
    context: ctx,
    actor: ctx.userEmail || ctx.actor || null
  };
  // Entity scope columns (all nullable in the schema)
  if (ctx.supplierId) {
    var s = resolveSupplierIds(null, ctx.supplierId);
    row.supplier_id = s.supplierId || null;
    row.supplier_entity_id = s.entityId || null;
  }
  if (ctx.buyerId) {
    var b = resolveBuyerIds(null, ctx.buyerId);
    row.buyer_id = b.buyerId || null;
    row.buyer_entity_id = b.entityId || null;
  }
  if (ctx.invoiceId) row.invoice_id = ctx.invoiceId;
  return row;
}

// Build an in-memory audit entry from a DB row. The shape matches the legacy
// in-memory format exactly — { timestamp, displayTime, action, details, context }
// — so the seven UI render sites need no changes.
function auditDbRowToEntry(row) {
  var ctx = row.context || {};
  return {
    timestamp: row.created_at,
    displayTime: formatAuditDisplayTime(row.created_at, ctx),
    action: row.event_type,
    details: row.details,
    context: ctx
  };
}

// Pack an in-memory SPQ entry into the new schema shape: 14 explicit columns
// plus a metadata JSONB carrying every legacy field. Inverse of unpackSpqRow.
function packSpqRow(item) {
  // Compute the parent + entity IDs from whatever the in-memory entry has.
  // After Stage 3, item.supplierId is always parent (no colon); item.entityId
  // (if present) is parent-or-composite. During the transition, supplierId may
  // still hold a composite — handle both.
  var entityId = item.supplierEntityId || item.entityId || item.supplierId || "";
  var parentId = parseEntityId(entityId).supplierId || entityId || "";
  // Defensive fallback: if no supplier resolved from the SPQ entry's own fields,
  // walk to the invoice (single or first of bundle) and use ITS supplierId. The
  // DB column is NOT NULL so sending null would reject the upsert. Without this,
  // bugs that fail to populate supplierId at SPQ creation time become silent
  // bundle-NOT-NULL violations at save time. Logged so the bug remains visible.
  if (!parentId) {
    var fallbackInvId = item.invoiceId || (Array.isArray(item.invoiceIds) ? item.invoiceIds[0] : null) || item.sourceInvoiceId || null;
    if (fallbackInvId) {
      var fallbackInv = INVOICES_DB.find(function(x) { return x.id === fallbackInvId; });
      if (fallbackInv && fallbackInv.supplierId) {
        var fbEntityId = fallbackInv.supplierId;
        var fbParentId = parseEntityId(fbEntityId).supplierId || fbEntityId;
        console.warn("[packSpqRow] Falling back to invoice supplier for SPQ " + item.id + ": " + fbParentId + " (entry had no supplierId — investigate creation path)");
        entityId = fbEntityId;
        parentId = fbParentId;
      }
    }
  }
  return {
    id: item.id,
    type: item.type,
    status: item.status || "Pending",
    amount: item.amount,
    currency: item.currency,
    date: item.date || null,
    supplier_id: parentId || null,
    supplier_entity_id: entityId || null,
    invoice_id: item.invoiceId || null,
    invoice_ids: item.invoiceIds || [],
    source_invoice_id: item.sourceInvoiceId || null,
    source_payment_id: item.sourcePaymentId || null,
    funding_program: item.programId || item.fundingProgram || null,
    metadata: {
      programName: item.programName || null,
      bankName: item.bankName || null,
      bankDetails: item.bankDetails || null,
      hbPaymentId: item.hbPaymentId || null,
      isBundle: !!item.isBundle,
      holdbackIds: item.holdbackIds || [],
      grossAmount: item.grossAmount != null ? item.grossAmount : null,
      deductions: item.deductions || [],
      deductionTotal: item.deductionTotal || 0,
      notes: item.notes || [],
      createdDisplay: item.createdDisplay || null,
      executedAt: item.executedAt || null,
      executedDisplay: item.executedDisplay || null,
      cancelledAt: item.cancelledAt || null,
      cancelledDisplay: item.cancelledDisplay || null,
      failedAt: item.failedAt || null,
      failedDisplay: item.failedDisplay || null
    }
  };
}

// Inverse of packSpqRow. Reconstructs the in-memory entry from a DB row,
// pulling stuffed fields back out of the metadata JSONB. Resolves the
// supplier display name from SUPPLIERS_DB.
function unpackSpqRow(row) {
  var meta = row.metadata || {};
  var ids = resolveSupplierIds(row.supplier_id, row.supplier_entity_id);
  return {
    id: row.id, type: row.type, invoiceId: row.invoice_id, invoiceIds: row.invoice_ids || [],
    supplierName: getEntityDisplayName(ids.entityId),
    supplierId: ids.entityId,            // composite when branch, parent when not — preserves prior in-memory shape
    supplierEntityId: ids.entityId,
    supplierParentId: ids.supplierId,
    bankName: meta.bankName || null,
    bankDetails: meta.bankDetails || null,
    amount: parseFloat(row.amount) || 0,
    currency: row.currency,
    status: row.status,
    programId: row.funding_program,
    programName: meta.programName || null,
    hbPaymentId: meta.hbPaymentId || null,
    sourceInvoiceId: row.source_invoice_id || null,
    isBundle: !!meta.isBundle,
    holdbackIds: meta.holdbackIds || [],
    grossAmount: meta.grossAmount != null ? parseFloat(meta.grossAmount) : null,
    deductions: meta.deductions || [],
    deductionTotal: parseFloat(meta.deductionTotal) || 0,
    notes: meta.notes || [],
    createdAt: row.created_at,
    createdDisplay: meta.createdDisplay || null,
    executedAt: meta.executedAt || null,
    executedDisplay: meta.executedDisplay || null,
    sourcePaymentId: row.source_payment_id || null,
    cancelledAt: meta.cancelledAt || null,
    cancelledDisplay: meta.cancelledDisplay || null,
    failedAt: meta.failedAt || null,
    failedDisplay: meta.failedDisplay || null,
    date: row.date || null
  };
}

// Map an invoices DB row into in-memory shape. supplier_name/buyer_name no longer
// exist in the schema; resolve display names via SUPPLIERS_DB / BUYERS_DB.
// Used by both the bulk loader and reloadInvoices and reloadForSupplier.
function unpackInvoiceRow(row) {
  var sIds = resolveSupplierIds(row.supplier_id, row.supplier_entity_id);
  var bIds = resolveBuyerIds(row.buyer_id, row.buyer_entity_id);
  return {
    id: row.id,
    supplierName: getEntityDisplayName(sIds.entityId),
    supplierId: sIds.entityId,
    supplierEntityId: sIds.entityId,
    supplierParentId: sIds.supplierId,
    buyerName: buyName(bIds.buyerId),
    buyerId: bIds.buyerId,
    buyerEntityId: bIds.entityId,
    amount: parseFloat(row.amount) || 0, currency: row.currency,
    capitalDue: parseFloat(row.capital_due) || 0, holdback: parseFloat(row.holdback) || 0,
    interestCharged: parseFloat(row.interest_charged) || 0, deferredPayment: parseFloat(row.deferred_payment) || 0,
    daysToMaturity: row.days_to_maturity || 0,
    advanceRate: parseFloat(row.advance_rate) || 0, annualRate: parseFloat(row.annual_rate) || 0, penaltyRate: parseFloat(row.penalty_rate) || 0,
    invoiceDate: row.invoice_date, dueDate: row.due_date, fundedDate: row.funded_date,
    createdDate: row.created_date, approvedDate: row.approved_date, fullyRepaidDate: row.fully_repaid_date,
    settledDate: row.settled_date,
    invoiceStatus: row.invoice_status, fundingStatus: row.funding_status,
    fundingProgram: row.funding_program, partialApprovedAmount: parseFloat(row.partial_approved_amount) || 0,
    invoiceReference: row.invoice_reference, purchaseOrder: row.purchase_order,
    buyerRef: row.buyer_ref, supplierRef: row.supplier_ref, buyerReceivedDate: row.buyer_received_date,
    invoiceStatusHistory: row.invoice_status_history || [],
    adjustments: row.adjustments || [],
    doNotFund: row.do_not_fund || false, doNotAdvance: row.do_not_advance || false,
    writtenDownShort: row.written_down_short || false, writeDownDate: row.write_down_date || null,
    pendingTopUpAmount: row.pending_top_up_amount || 0, pendingTopUpRate: row.pending_top_up_rate || null, pendingTopUpDate: row.pending_top_up_date || null,
    tranches: row.tranches || [],
    voided: row.voided || false, voidedAt: row.voided_at || null, voidedBy: row.voided_by || null, voidReason: row.void_reason || null,
    notes: row.notes || [],
    csvAmountPaid: row.csv_amount_paid != null ? parseFloat(row.csv_amount_paid) : null,
    intendedPaymentDate: row.intended_payment_date || null
  };
}

// Pack an in-memory invoice into a DB row — drops supplier_name/buyer_name, adds
// *_entity_id columns. Used by saveInvoice and the bulk savePersistedData path.
function packInvoiceRow(inv) {
  var entityId = inv.supplierEntityId || inv.supplierId || "";
  var parentId = parseEntityId(entityId).supplierId || entityId || "";
  var bEntity = inv.buyerEntityId || inv.buyerId || "";
  var bParent = bEntity.indexOf(":") > -1 ? bEntity.split(":")[0] : (bEntity || "");
  return {
    id: inv.id,
    supplier_id: parentId,
    supplier_entity_id: entityId,
    buyer_id: bParent,
    buyer_entity_id: bEntity,
    amount: inv.amount, currency: inv.currency,
    capital_due: inv.capitalDue || 0, holdback: inv.holdback || 0,
    interest_charged: inv.interestCharged || 0, deferred_payment: inv.deferredPayment || 0,
    days_to_maturity: inv.daysToMaturity || 0,
    advance_rate: inv.advanceRate || 0, annual_rate: inv.annualRate || 0, penalty_rate: inv.penaltyRate || 0,
    invoice_date: inv.invoiceDate, due_date: inv.dueDate, funded_date: inv.fundedDate,
    created_date: inv.createdDate, approved_date: inv.approvedDate, fully_repaid_date: inv.fullyRepaidDate,
    settled_date: inv.settledDate || null,
    invoice_status: inv.invoiceStatus, funding_status: inv.fundingStatus,
    funding_program: inv.fundingProgram || null,
    partial_approved_amount: inv.partialApprovedAmount || 0,
    invoice_reference: inv.invoiceReference || null, purchase_order: inv.purchaseOrder || null,
    buyer_ref: inv.buyerRef || null, supplier_ref: inv.supplierRef || null, buyer_received_date: inv.buyerReceivedDate || null,
    invoice_status_history: inv.invoiceStatusHistory || [],
    adjustments: inv.adjustments || [],
    do_not_fund: inv.doNotFund || false, do_not_advance: inv.doNotAdvance || false,
    written_down_short: inv.writtenDownShort || false, write_down_date: inv.writeDownDate || null,
    pending_top_up_amount: inv.pendingTopUpAmount || 0, pending_top_up_rate: inv.pendingTopUpRate || null, pending_top_up_date: inv.pendingTopUpDate || null,
    tranches: inv.tranches || [],
    voided: inv.voided || false, voided_at: inv.voidedAt || null, voided_by: inv.voidedBy || null, void_reason: inv.voidReason || null,
    current_invoice_status: inv.currentInvoiceStatus || null,
    disputed_date: inv.disputedDate || null,
    notes: inv.notes || []
  };
}

// Pack derived persisted fields onto an invoice row dictionary in-place.
// Used by saveInvoice (inline) — kept separate so persistDerivedFieldsForInvoices
// can reuse the same logic if it ever calls a row-builder.
function attachDerivedFieldsToRow(row, inv) {
  row.capital_outstanding = (inv.capitalOutstanding === undefined || inv.capitalOutstanding === null) ? null : inv.capitalOutstanding;
  row.interest_outstanding = (inv.interestOutstanding === undefined || inv.interestOutstanding === null) ? null : inv.interestOutstanding;
  row.penalty_outstanding = (inv.penaltyOutstanding === undefined || inv.penaltyOutstanding === null) ? null : inv.penaltyOutstanding;
  row.holdback_outstanding = (inv.holdbackOutstanding === undefined || inv.holdbackOutstanding === null) ? null : inv.holdbackOutstanding;
  row.holdback_overdrawn = (inv.holdbackOverdrawn === undefined || inv.holdbackOverdrawn === null) ? null : inv.holdbackOverdrawn;
  row.debt_balance = (inv.debtBalance === undefined || inv.debtBalance === null) ? null : inv.debtBalance;
  row.balance_owed = (inv.balanceOwed === undefined || inv.balanceOwed === null) ? null : inv.balanceOwed;
  row.amount_post_dilutions = (inv.amountPostDilutions === undefined || inv.amountPostDilutions === null) ? null : inv.amountPostDilutions;
}

// Pack a credit note in-memory entry into a DB row.
function packCreditNoteRow(cn) {
  var entityId = cn.supplierEntityId || cn.supplierId || "";
  var parentId = parseEntityId(entityId).supplierId || entityId || "";
  var bEntity = cn.buyerEntityId || cn.buyerId || "";
  var bParent = bEntity.indexOf(":") > -1 ? bEntity.split(":")[0] : (bEntity || "");
  return {
    credit_note_id: cn.creditNoteId, amount: cn.amount, currency: cn.currency,
    date: cn.date, reference: cn.reference || "",
    supplier_id: parentId, supplier_entity_id: entityId,
    buyer_id: bParent, buyer_entity_id: bEntity,
    allocations: cn.allocations || [], notes: cn.notes || [],
    voided: cn.voided || false, voided_at: cn.voidedAt || null, voided_by: cn.voidedBy || null, void_reason: cn.voidReason || null,
    created_display: cn.createdDisplay || null
  };
}

// Unpack a credit_notes DB row into in-memory shape.
function unpackCreditNoteRow(row) {
  var sIds = resolveSupplierIds(row.supplier_id, row.supplier_entity_id);
  var bIds = resolveBuyerIds(row.buyer_id, row.buyer_entity_id);
  return {
    creditNoteId: row.credit_note_id, amount: parseFloat(row.amount) || 0,
    currency: row.currency, date: row.date, reference: row.reference || "",
    supplierName: getEntityDisplayName(sIds.entityId),
    supplierId: sIds.entityId,
    supplierEntityId: sIds.entityId,
    supplierParentId: sIds.supplierId,
    buyerName: buyName(bIds.buyerId),
    buyerId: bIds.buyerId,
    buyerEntityId: bIds.entityId,
    createdDisplay: row.created_display, allocations: row.allocations || [],
    notes: row.notes || [],
    voided: row.voided || false, voidedAt: row.voided_at || null, voidedBy: row.voided_by || null, voidReason: row.void_reason || null
  };
}

// Resolve the parent + entity ID for a given invoice ID, looking up INVOICES_DB.
// Used to populate the denormalised supplier_id / supplier_entity_id columns
// on payment_allocations and holdback_payment_allocations rows.
function getSupplierIdsForInvoice(invoiceId) {
  if (!invoiceId) return { supplierId: null, entityId: null };
  var inv = INVOICES_DB.find(function(x) { return x.id === invoiceId; });
  if (!inv) return { supplierId: null, entityId: null };
  var entityId = inv.supplierEntityId || inv.supplierId || "";
  var parentId = inv.supplierParentId || parseEntityId(entityId).supplierId || entityId || "";
  return { supplierId: parentId, entityId: entityId };
}

function getSupplierBankDetails(entityId, programId) {
  var sup = getSupplierById(entityId);
  if (!sup) return { bankName: "", bankDetails: "", bankVerified: false };
  var branch = getBranchById(entityId);
  // 1. Branch program-specific
  if (programId && branch && branch.programBankAccounts && branch.programBankAccounts[programId]) {
    var brProgAcct = branch.programBankAccounts[programId].outgoing || {};
    if (brProgAcct.bankName) {
      var details = [brProgAcct.sortCode, brProgAcct.accountNumber, brProgAcct.iban, brProgAcct.aba, brProgAcct.bic].filter(Boolean).join(" / ");
      return { bankName: brProgAcct.bankName, bankDetails: details, bankVerified: brProgAcct.verified || false };
    }
  }
  // 2. Parent program-specific
  if (programId && sup.programBankAccounts && sup.programBankAccounts[programId]) {
    var progAcct = sup.programBankAccounts[programId].outgoing || {};
    if (progAcct.bankName) {
      var details = [progAcct.sortCode, progAcct.accountNumber, progAcct.iban, progAcct.aba, progAcct.bic].filter(Boolean).join(" / ");
      return { bankName: progAcct.bankName, bankDetails: details, bankVerified: progAcct.verified || false };
    }
  }
  // 3. Branch flat
  if (branch && branch.bankName) return { bankName: branch.bankName, bankDetails: branch.bankDetails || "", bankVerified: branch.bankVerified || false };
  // 4. Parent flat
  return { bankName: sup.bankName || "", bankDetails: sup.bankDetails || "", bankVerified: sup.bankVerified || false };
}

// Look up a supplier's rate for a specific program at a given point in time.
// Returns null if the supplier has no rates set for that program.
// History is stored as supplier.programRates[programId] in one of two shapes:
//   OLD:  [history-entries...]                 — flat array, pre-rate-chain work
//   NEW:  { "__default": [history-entries...], "BUY-001": [history-entries...] }
//         — dict keyed by buyerId, with "__default" as the catch-all
// We resolve the buyer-keyed entry first when a buyerId is supplied, then fall
// back to "__default". Old-shape arrays are treated as "__default" for
// backward compatibility — the JSX reads them transparently regardless of
// whether the data has been migrated to the new shape.
// We pick the most recent entry whose effectiveTimestamp <= asOfTimestamp.
function _resolveProgramRateHistory(pr, programId, buyerId) {
  if (!pr) return null;
  var entry = pr[programId];
  if (!entry) return null;
  // Old shape: a bare array. Treat as "__default".
  if (Array.isArray(entry)) return entry;
  // New shape: dict. Try buyer-specific first, then default.
  if (buyerId && Array.isArray(entry[buyerId])) return entry[buyerId];
  if (Array.isArray(entry["__default"])) return entry["__default"];
  return null;
}

// Returns every per-buyer rate key under (supplier.programRates[programId])
// EXCLUDING "__default" and EXCLUDING keys whose latest history entry is a
// soft-delete sentinel (the override has been removed). For old-shape (bare
// array) returns []. Order is insertion order (Object.keys), which roughly
// tracks the order the operator added them.
function _listPerBuyerRateKeys(pr, programId) {
  if (!pr || !pr[programId]) return [];
  var entry = pr[programId];
  if (Array.isArray(entry)) return [];
  return Object.keys(entry).filter(function(k) {
    if (k === "__default") return false;
    var hist = entry[k];
    if (!Array.isArray(hist) || hist.length === 0) return false;
    // Latest entry (sort by effectiveTimestamp/effectiveDate). If latest is
    // a removal sentinel, this buyer has no active override.
    var sorted = hist.slice().sort(function(a, b) { return (b.effectiveTimestamp || b.effectiveDate).localeCompare(a.effectiveTimestamp || a.effectiveDate); });
    return !sorted[0].removed;
  });
}

// Companion to _listPerBuyerRateKeys: return per-buyer keys whose LATEST
// history entry is the soft-delete sentinel — i.e. overrides that were
// removed and could be restored. Excludes keys with empty history (an
// override that was added then immediately undone before any "real" rate
// existed isn't worth restoring; there's nothing to restore TO).
function _listRemovedBuyerRateKeys(pr, programId) {
  if (!pr || !pr[programId]) return [];
  var entry = pr[programId];
  if (Array.isArray(entry)) return [];
  return Object.keys(entry).filter(function(k) {
    if (k === "__default") return false;
    var hist = entry[k];
    if (!Array.isArray(hist) || hist.length === 0) return false;
    var sorted = hist.slice().sort(function(a, b) { return (b.effectiveTimestamp || b.effectiveDate).localeCompare(a.effectiveTimestamp || a.effectiveDate); });
    if (!sorted[0].removed) return false;
    // Require at least one prior non-removed entry to restore from.
    return sorted.some(function(h) { return !h.removed; });
  });
}

// For a per-buyer key whose latest entry is a removal, return the most
// recent non-removed entry (i.e. the rate the override held before it was
// soft-deleted). Used by the restore flow to pre-fill the edit form.
// Returns null if no prior non-removed entry exists.
function _lastActiveBuyerRateEntry(pr, programId, buyerKey) {
  if (!pr || !pr[programId]) return null;
  var entry = pr[programId];
  if (Array.isArray(entry)) return null;
  var hist = entry[buyerKey];
  if (!Array.isArray(hist) || hist.length === 0) return null;
  var sorted = hist.slice().sort(function(a, b) { return (b.effectiveTimestamp || b.effectiveDate).localeCompare(a.effectiveTimestamp || a.effectiveDate); });
  for (var i = 0; i < sorted.length; i++) {
    if (!sorted[i].removed) return sorted[i];
  }
  return null;
}

// Push a new rate entry to (supplier.programRates[programId][buyerKey]). When
// buyerKey is null/undefined/"__default", writes to the default slot. Handles
// shape migration: if the current entry is the old bare-array shape, converts
// to the dict shape (preserving the existing array as "__default") before
// adding the per-buyer entry.
//
// MUTATES the passed programRates object in place. Caller is responsible for
// invoking saveSupplier after this to persist.
function _pushProgramRateEntry(programRates, programId, buyerKey, entry) {
  if (!programRates[programId]) programRates[programId] = [];
  var current = programRates[programId];
  var key = buyerKey || "__default";
  if (Array.isArray(current)) {
    // Old shape. If writing to default, we can keep the array shape; the
    // resolver treats bare arrays as "__default" anyway. But if writing
    // to a non-default key, we must convert.
    if (key === "__default") {
      current.push(entry);
      return;
    }
    // Convert old shape → dict, preserving the existing array as the default
    programRates[programId] = { "__default": current.slice(), };
    programRates[programId][key] = [entry];
    return;
  }
  // Dict shape — append to (or create) the target key's array
  if (!Array.isArray(current[key])) current[key] = [];
  current[key].push(entry);
}

function getSupplierRateForProgram(entityId, programId, asOfTimestamp, buyerId) {
  if (!programId) return null;
  var supplier = getSupplierById(entityId);
  if (!supplier) supplier = SUPPLIERS_DB.find(function(s) { return s.name === entityId; });
  if (!supplier) return null;
  var arr = _resolveProgramRateHistory(supplier.programRates, programId, buyerId || null);
  if (!arr || arr.length === 0) return null;
  var ts = asOfTimestamp || new Date().toISOString();
  var sorted = arr.slice().sort(function(a, b) { return (a.effectiveTimestamp || a.effectiveDate).localeCompare(b.effectiveTimestamp || b.effectiveDate); });
  var rate = null;
  for (var i = 0; i < sorted.length; i++) {
    var rts = sorted[i].effectiveTimestamp || sorted[i].effectiveDate;
    if (rts <= ts) rate = sorted[i];
  }
  // If asOfTimestamp is before any rate's effectiveTimestamp, no rate was in effect → null.
  if (!rate) return null;
  // Soft-delete sentinel: if the most-recent applicable entry is `removed: true`,
  // this buyer's override has been (or was, at asOfTimestamp) removed. Fall
  // through to the default — same semantic as never having an override.
  // The sentinel itself is just a marker; we don't fund at its 0/0/0 rates.
  // Note: we only fall through if we were resolving a buyer-specific override.
  // If the default itself somehow got a removal sentinel as latest, we return
  // null (no rate) — that's a misconfigured supplier and shouldn't fund.
  if (rate.removed) {
    if (buyerId) {
      // Retry with the default (no buyer-specific lookup)
      return getSupplierRateForProgram(entityId, programId, asOfTimestamp, null);
    }
    return null;
  }
  return { advanceRate: rate.advanceRate !== undefined ? rate.advanceRate : ADVANCE_RATE, annualRate: rate.annualRate, penaltyRate: rate.penaltyRate };
}

// Backward-compat: returns the rate of the first program the supplier has rates for, or
// system defaults. Used by display code (cards, forms, summaries) where program context
// may not be available. Eligibility checks should always use getSupplierRateForProgram.
function getSupplierRate(entityId, asOfTimestamp) {
  var supplier = getSupplierById(entityId);
  if (!supplier) supplier = SUPPLIERS_DB.find(function(s) { return s.name === entityId; });
  if (!supplier) return { advanceRate: ADVANCE_RATE, annualRate: ANNUAL_RATE, penaltyRate: PENALTY_RATE };
  var pr = supplier.programRates || {};
  var keys = Object.keys(pr);
  for (var i = 0; i < keys.length; i++) {
    var r = getSupplierRateForProgram(entityId, keys[i], asOfTimestamp);
    if (r) return r;
  }
  return { advanceRate: ADVANCE_RATE, annualRate: ANNUAL_RATE, penaltyRate: PENALTY_RATE };
}

// ======== Benchmark helpers (placeholder stubs) ========
// The rate-chain architecture is a schema-only landing in this pass. These
// stubs let the rest of the codebase reference benchmarks without crashing,
// and define the call signatures the future recomputation engine will use.
// None of the existing call sites use these — they read materialised rate
// values (inv.annualRate etc) directly. See branch_cascade_and_rate_architecture.sql
// for the full rateDefinition spec.
function getBenchmark(benchmarkId) {
  if (!benchmarkId) return null;
  return BENCHMARKS_DB.find(function(b) { return b.id === benchmarkId; }) || null;
}

// Resolve a rateDefinition object into a numeric rate. Currently only the
// "fixed" mode is supported; the benchmark/buyer/parent modes are
// placeholder-returns-null until the recomputation engine is built.
// context (optional): { benchmark, parentRate, buyerRate } — values the
// future engine will pass in so this function can resolve chained modes.
function resolveRateDefinition(def, context) {
  if (!def || typeof def !== "object") return null;
  if (def.mode === "fixed") return (typeof def.value === "number") ? def.value : null;
  // benchmark / buyer / parent modes intentionally not yet implemented.
  // Returning null means callers fall back to the materialised numeric rate
  // already stored on the entry (annualRate / penaltyRate / advanceRate),
  // which is the source of truth until the engine is in place.
  return null;
}

// Programs the given supplier ID participates in (member of eligible_suppliers).
// Used to populate the program filter dropdown on the Suppliers view (Tweak #1).
function programsForSupplier(supplierId) {
  if (!supplierId) return [];
  var parentId = getParentEntityId(supplierId) || supplierId;
  return FUNDING_PROGRAMS_DB.filter(function(fp) {
    var elig = fp.eligibleSuppliers || [];
    return elig.indexOf(supplierId) > -1 || elig.indexOf(parentId) > -1;
  });
}

// Programs the given buyer ID participates in. Used for the Buyers view filter (Tweak #2).
function programsForBuyer(buyerId) {
  if (!buyerId) return [];
  // Composite "BUY-001:BR-001" resolves to its parent for eligibility — programs
  // list eligible buyers at the parent level, branches inherit their parent's
  // program eligibility. (Branch-specific program restrictions would be a
  // future feature; not on the roadmap.)
  var parentId = parseEntityId(buyerId).supplierId || buyerId;
  return FUNDING_PROGRAMS_DB.filter(function(fp) {
    return (fp.eligibleBuyers || []).indexOf(parentId) > -1;
  });
}

// True if the invoice belongs to (or could belong to) the given program. Used by all
// view filters that previously checked currency match. An invoice belongs to a program
// scope if it's been funded by that program OR (it's not yet funded but) the program
// would be eligible to fund it (currency match + supplier/buyer in eligible lists).
function invInProgramScope(inv, programId) {
  if (!programId) return true;
  if (inv.fundingProgram === programId) return true;
  // Unfunded invoices: include if program currency matches and supplier+buyer are eligible
  if (!inv.fundingProgram) {
    var fp = FUNDING_PROGRAMS_DB.find(function(p) { return p.id === programId; });
    if (!fp) return false;
    if (fp.currency && inv.currency && fp.currency !== inv.currency) return false;
    var supId = inv.supplierId || "";
    var supParent = getParentEntityId(supId) || supId;
    var supEligible = (fp.eligibleSuppliers || []).indexOf(supId) > -1 || (fp.eligibleSuppliers || []).indexOf(supParent) > -1;
    if (!supEligible) return false;
    // Buyer-side: check composite (inv.buyerEntityId or inv.buyerId — could be
    // either shape depending on creation path) AND parent. Match if EITHER is
    // in eligibleBuyers — operator may have added just the parent, just the
    // branch, or both.
    var buyEntityId = inv.buyerEntityId || inv.buyerId || "";
    var buyParent = parseEntityId(buyEntityId).supplierId || buyEntityId;
    var buyEligible = (fp.eligibleBuyers || []).indexOf(buyEntityId) > -1 || (fp.eligibleBuyers || []).indexOf(buyParent) > -1;
    if (!buyEligible) return false;
    return true;
  }
  return false;
}

function getEligiblePrograms(inv, supDilRates) {
  var entityIdForRate = inv.supplierId || inv.supplierName;
  var parentId = getParentEntityId(inv.supplierId || "");
  var parentSup = getParentSupplierName(inv.supplierName);
  var term = inv.daysToMaturity || (inv.invoiceDate && inv.dueDate ? daysBetween(inv.invoiceDate, inv.dueDate) : 0);
  // Ineligible invoice statuses
  var badInvStatuses = { "Settled": true, "Cancelled": true, "Declined": true, "Disputed": true, "Buyer Default": true };
  if (badInvStatuses[inv.invoiceStatus]) return [];
  var dr = supDilRates ? (supDilRates[parentId] || supDilRates[parentSup] || {}) : {};
  return FUNDING_PROGRAMS_DB.filter(function(fp) {
    // Currency must match — a program in EUR cannot fund a GBP invoice and vice versa
    if (fp.currency && inv.currency && fp.currency !== inv.currency) return false;
    // Eligible suppliers check — by ID (parent or entity)
    if (fp.eligibleSuppliers && fp.eligibleSuppliers.length > 0) {
      var entityId = inv.supplierId || "";
      var idMatch = fp.eligibleSuppliers.indexOf(entityId) > -1 || fp.eligibleSuppliers.indexOf(parentId) > -1;
      if (!idMatch) return false;
    }
    // Eligible buyers check — by ID. Check both the composite (entity or
    // parent) so a program that lists only the branch matches an invoice
    // raised under that branch, and a program that lists only the parent
    // matches all of its branches' invoices.
    if (fp.eligibleBuyers && fp.eligibleBuyers.length > 0) {
      var buyEntityId = inv.buyerEntityId || inv.buyerId || "";
      var buyParent = parseEntityId(buyEntityId).supplierId || buyEntityId;
      var buyMatch = fp.eligibleBuyers.indexOf(buyEntityId) > -1 || fp.eligibleBuyers.indexOf(buyParent) > -1;
      if (!buyMatch) return false;
    }
    // Per-program rate lookup. No rate = supplier hasn't been commercially configured for this
    // program yet → ineligible. Falls through the gate at program-add time.
    // Buyer-scoped: per-buyer rate overrides take precedence over the default
    // (see _resolveProgramRateHistory). Passing the composite buyerEntityId
    // lets a branch-specific override beat the parent override beat the default.
    var elgBuyerKey = inv.buyerEntityId || inv.buyerId || null;
    var supRate = getSupplierRateForProgram(entityIdForRate, fp.id, null, elgBuyerKey) || getSupplierRateForProgram(parentId, fp.id, null, elgBuyerKey);
    if (!supRate) return false;
    if (supRate.annualRate < fp.minInterestRate - 0.0001) return false;
    if (supRate.advanceRate > fp.maxAdvanceRate + 0.0001) return false;
    if (term > fp.maxInvoiceTerm) return false;
    if (fp.minInvoiceTenor && term < fp.minInvoiceTenor) return false;
    if (fp.minInvoiceSize && inv.amount < fp.minInvoiceSize) return false;
    if (fp.maxSupDilLive && dr.dilRate > fp.maxSupDilLive) return false;
    if (fp.maxSupDil30 && dr.dil30 > fp.maxSupDil30) return false;
    if (fp.maxSupDil90 && dr.dil90 > fp.maxSupDil90) return false;
    if (fp.maxFundDilLive && dr.fdilRate > fp.maxFundDilLive) return false;
    if (fp.maxFundDil30 && dr.fdil30 > fp.maxFundDil30) return false;
    if (fp.maxFundDil90 && dr.fdil90 > fp.maxFundDil90) return false;
    // Cascading single-invoice limit checks. Each function evaluates both
    // parent's cap and (if invoice is on a branch) the branch's cap.
    // Returns null on pass, string reason on fail; eligibility just cares
    // about pass/fail here — getEligibilityReasons surfaces the message.
    if (checkSupplierProgramCascadingSingleInvoiceLimit(inv, fp.id)) return false;
    if (checkBuyerProgramCascadingSingleInvoiceLimit(inv, fp.id)) return false;
    return true;
  });
}

// Diagnostic counterpart of getEligiblePrograms — walks the same checks but
// accumulates a human-readable reason for each rejection. Used by the
// "Not eligible" tooltip on Unpurchased Invoices and the supplier portal.
// Returns { eligibleCount, rejections: [{ programName, programId, reasons: [string] }] }.
function getEligibilityReasons(inv, supDilRates) {
  var entityIdForRate = inv.supplierId || inv.supplierName;
  var parentId = getParentEntityId(inv.supplierId || "");
  var parentSup = getParentSupplierName(inv.supplierName);
  var term = inv.daysToMaturity || (inv.invoiceDate && inv.dueDate ? daysBetween(inv.invoiceDate, inv.dueDate) : 0);
  var badInvStatuses = { "Settled": true, "Cancelled": true, "Declined": true, "Disputed": true, "Buyer Default": true };
  // Invoice-level rejection (applies to all programs at once)
  if (badInvStatuses[inv.invoiceStatus]) {
    return { eligibleCount: 0, invoiceLevelReason: "Invoice status \"" + inv.invoiceStatus + "\" is ineligible for funding", rejections: [] };
  }
  var dr = supDilRates ? (supDilRates[parentId] || supDilRates[parentSup] || {}) : {};
  var eligibleCount = 0;
  var rejections = [];
  FUNDING_PROGRAMS_DB.forEach(function(fp) {
    var reasons = [];
    if (fp.currency && inv.currency && fp.currency !== inv.currency) {
      reasons.push("Currency mismatch (program is " + fp.currency + ", invoice is " + inv.currency + ")");
    }
    if (fp.eligibleSuppliers && fp.eligibleSuppliers.length > 0) {
      var entityId = inv.supplierId || "";
      var idMatch = fp.eligibleSuppliers.indexOf(entityId) > -1 || fp.eligibleSuppliers.indexOf(parentId) > -1;
      if (!idMatch) reasons.push("Supplier not on program's eligible list");
    }
    if (fp.eligibleBuyers && fp.eligibleBuyers.length > 0) {
      var buyerId = inv.buyerId || "";
      if (fp.eligibleBuyers.indexOf(buyerId) === -1) reasons.push("Buyer not on program's eligible list");
    }
    var elgRBuyerKey = inv.buyerEntityId || inv.buyerId || null;
    var supRate = getSupplierRateForProgram(entityIdForRate, fp.id, null, elgRBuyerKey) || getSupplierRateForProgram(parentId, fp.id, null, elgRBuyerKey);
    if (!supRate) {
      reasons.push("No commercial rate configured for this supplier on this program");
    } else {
      if (supRate.annualRate < fp.minInterestRate - 0.0001) {
        reasons.push("Supplier rate " + (supRate.annualRate * 100).toFixed(2) + "% is below program minimum " + (fp.minInterestRate * 100).toFixed(2) + "%");
      }
      if (supRate.advanceRate > fp.maxAdvanceRate + 0.0001) {
        reasons.push("Supplier advance rate " + (supRate.advanceRate * 100).toFixed(1) + "% exceeds program maximum " + (fp.maxAdvanceRate * 100).toFixed(1) + "%");
      }
    }
    if (term > fp.maxInvoiceTerm) reasons.push("Invoice term " + term + "d exceeds program max " + fp.maxInvoiceTerm + "d");
    if (fp.minInvoiceTenor && term < fp.minInvoiceTenor) reasons.push("Invoice term " + term + "d below program min " + fp.minInvoiceTenor + "d");
    if (fp.minInvoiceSize && inv.amount < fp.minInvoiceSize) {
      reasons.push("Invoice amount " + money(inv.amount, inv.currency) + " below program min " + money(fp.minInvoiceSize, fp.currency));
    }
    if (fp.maxSupDilLive && dr.dilRate > fp.maxSupDilLive) reasons.push("Supplier live dilution exceeds program limit");
    if (fp.maxSupDil30 && dr.dil30 > fp.maxSupDil30) reasons.push("Supplier 30-day dilution exceeds program limit");
    if (fp.maxSupDil90 && dr.dil90 > fp.maxSupDil90) reasons.push("Supplier 90-day dilution exceeds program limit");
    if (fp.maxFundDilLive && dr.fdilRate > fp.maxFundDilLive) reasons.push("Funded live dilution exceeds program limit");
    if (fp.maxFundDil30 && dr.fdil30 > fp.maxFundDil30) reasons.push("Funded 30-day dilution exceeds program limit");
    if (fp.maxFundDil90 && dr.fdil90 > fp.maxFundDil90) reasons.push("Funded 90-day dilution exceeds program limit");
    // Cascading single-invoice limit checks — each returns null on pass or
    // the specific reason string on fail. The string already tells the
    // operator whether the parent's or the branch's cap was breached.
    var supSilReason = checkSupplierProgramCascadingSingleInvoiceLimit(inv, fp.id);
    if (supSilReason) reasons.push(supSilReason);
    var buySilReason = checkBuyerProgramCascadingSingleInvoiceLimit(inv, fp.id);
    if (buySilReason) reasons.push(buySilReason);
    if (reasons.length === 0) {
      eligibleCount += 1;
    } else {
      rejections.push({ programId: fp.id, programName: fp.name, reasons: reasons });
    }
  });
  return { eligibleCount: eligibleCount, rejections: rejections };
}

// Compute the maximum capital any eligible program could offer for this invoice
function getMaxAvailableCapital(inv, supDilRates, cnDilutionTotal, buyerCollected) {
  var eligible = getEligiblePrograms(inv, supDilRates);
  if (eligible.length === 0) return 0;
  // Effective fundable base:
  //  - cap at invoice amount (always)
  //  - cap at partialApprovedAmount if the invoice is Approved in Part (buyer won't pay more than that)
  //  - cap at amount minus any credit-note dilutions already applied
  //  - cap at amount minus any buyer payments already collected (the collected portion is no longer a receivable)
  // Funding advance rate applies to the lowest of these.
  var partial = (inv.invoiceStatus === "Approved in Part" && inv.partialApprovedAmount > 0) ? inv.partialApprovedAmount : inv.amount;
  var postDilutions = inv.amount - (cnDilutionTotal || 0);
  var postCollected = inv.amount - (buyerCollected || 0);
  var effectiveBase = Math.max(0, Math.min(inv.amount, partial, postDilutions, postCollected));
  if (effectiveBase <= 0) return 0;
  var maxCap = 0;
  eligible.forEach(function(fp) {
    var cap = r2(effectiveBase * fp.maxAdvanceRate);
    if (cap > maxCap) maxCap = cap;
  });
  return maxCap;
}

function generateData(count) {
  var rand = makeRng(42), invoices = [], rawPayments = [], payId = 0;
  for (var i = 0; i < count; i++) {
    var id = "INV-" + String(i + 1001).padStart(7, "0");
    var buyer = BUYERS[Math.floor(rand() * 8)];
    var ccy = CURRENCIES[Math.floor(rand() * 3)];
    var amt = r6(5000 + rand() * 95000);
    var capitalDue = r2(amt * ADVANCE_RATE);
    var holdback = r2(r2(amt) - capitalDue);
    var daysAgo = Math.floor(rand() * 240);
    var invDate = addDays(REF_DATE, -daysAgo);
    var dueDays = 30 + Math.floor(rand() * 61);
    var dueDate = addDays(invDate, dueDays);
    var pastDue = dueDate < REF_DATE;
    var interestDays = daysBetween(invDate, dueDate);
    var interestCharged = r2(capitalDue * DAILY_RATE * interestDays);
    var deferredPayment = r2(holdback - interestCharged);
    var hist = [{ status: "Received", date: invDate }];
    var status = "Received", repaid = 0, frDate = null, partial = 0;
    var rv = rand();
    if (daysAgo < 5) { /* Received */ }
    else if (rv < 0.05) {
      hist.push({ status: "Declined", date: addDays(invDate, 3 + Math.floor(rand() * 7)) });
      status = "Declined";
    } else if (rv < 0.12) {
      var dd2 = addDays(invDate, 3 + Math.floor(rand() * 10));
      hist.push({ status: "Disputed", date: dd2 });
      if (daysAgo < 20) { status = "Disputed"; }
      else if (rand() < 0.5) {
        hist.push({ status: "Approved in Full", date: addDays(dd2, 5 + Math.floor(rand() * 10)) });
        if (pastDue) {
          var pd1 = addDays(dueDate, -Math.floor(rand() * 5));
          hist.push({ status: "Settled", date: pd1 }); status = "Settled"; repaid = amt; frDate = pd1;
          payId++; rawPayments.push({ paymentId: "PAY-" + String(payId).padStart(7, "0"), amount: amt, date: pd1, currency: ccy, allocations: [{ invoiceId: id, amount: amt }] });
        } else status = "Approved in Full";
      } else {
        hist.push({ status: "Approved in Part", date: addDays(dd2, 5 + Math.floor(rand() * 10)) });
        partial = r6(amt * (0.4 + rand() * 0.4));
        if (pastDue) {
          var pd2 = addDays(dueDate, -Math.floor(rand() * 5));
          hist.push({ status: "Settled", date: pd2 }); status = "Settled"; repaid = partial;
          payId++; rawPayments.push({ paymentId: "PAY-" + String(payId).padStart(7, "0"), amount: partial, date: pd2, currency: ccy, allocations: [{ invoiceId: id, amount: partial }] });
        } else status = "Approved in Part";
      }
    } else {
      var apd = addDays(invDate, 5 + Math.floor(rand() * 15));
      if (daysAgo < 8) { /* Received */ }
      else {
        hist.push({ status: "Approved in Full", date: apd });
        var r3 = rand();
        if (r3 < 0.05) {
          hist.push({ status: "Declined", date: addDays(apd, 3 + Math.floor(rand() * 10)) }); status = "Declined";
        } else if (r3 < 0.10) {
          partial = r6(amt * (0.4 + rand() * 0.45));
          hist.push({ status: "Approved in Part", date: addDays(apd, 2 + Math.floor(rand() * 8)) });
          if (pastDue) {
            var pd3 = addDays(dueDate, -Math.floor(rand() * 3));
            hist.push({ status: "Settled", date: pd3 }); status = "Settled"; repaid = partial;
            var np1 = 1 + Math.floor(rand() * 2), rem1 = partial;
            for (var p1 = 0; p1 < np1; p1++) {
              var pa1 = p1 === np1 - 1 ? r6(rem1) : r6(rem1 * (0.4 + rand() * 0.3));
              var ppd1 = addDays(pd3, -(np1 - 1 - p1) * Math.floor(rand() * 10 + 3));
              payId++; rawPayments.push({ paymentId: "PAY-" + String(payId).padStart(7, "0"), amount: pa1, date: ppd1, currency: ccy, allocations: [{ invoiceId: id, amount: pa1 }] });
              rem1 -= pa1; if (rem1 <= 0.01) break;
            }
          } else status = "Approved in Part";
        } else {
          if (pastDue) {
            var pd4 = addDays(dueDate, -Math.floor(rand() * 7));
            hist.push({ status: "Settled", date: pd4 }); status = "Settled"; repaid = amt; frDate = pd4;
            var np2 = 1 + Math.floor(rand() * 3), rem2 = amt;
            for (var p2 = 0; p2 < np2; p2++) {
              var pa2 = p2 === np2 - 1 ? r6(rem2) : r6(rem2 * (0.25 + rand() * 0.4));
              var ppd2 = addDays(pd4, -(np2 - 1 - p2) * Math.floor(rand() * 12 + 3));
              payId++; rawPayments.push({ paymentId: "PAY-" + String(payId).padStart(7, "0"), amount: pa2, date: ppd2, currency: ccy, allocations: [{ invoiceId: id, amount: pa2 }] });
              rem2 -= pa2; if (rem2 <= 0.01) break;
            }
          } else status = "Approved in Full";
        }
      }
    }
    invoices.push({ id: id, supplierName: SUPPLIER.name, buyerName: buyer, amount: amt, currency: ccy, capitalDue: capitalDue, holdback: holdback, interestCharged: interestCharged, deferredPayment: deferredPayment, daysToMaturity: interestDays, invoiceDate: invDate, dueDate: dueDate, fundedDate: invDate, createdDate: invDate, fullyRepaidDate: frDate, invoiceStatus: status, invoiceStatusHistory: hist, fundingStatus: "funded", partialApprovedAmount: partial });
  }
  // Test invoices
  [
    { id: "INV-TEST-001", buyer: "Apex Manufacturing Co", ccy: "GBP", amt: 42000, invDate: addDays(REF_DATE, -72), duo: 60, flow: [{ status: "Approved in Full", offset: 8 }] },
    { id: "INV-TEST-002", buyer: "Sterling Industries PLC", ccy: "EUR", amt: 28500, invDate: addDays(REF_DATE, -30), duo: 60, flow: [{ status: "Disputed", offset: 25 }] },
    { id: "INV-TEST-003", buyer: "Northgate Electronics", ccy: "GBP", amt: 67000, invDate: addDays(REF_DATE, -170), duo: 90, flow: [{ status: "Approved in Full", offset: 10 }] },
    { id: "INV-TEST-004", buyer: "Cascade Systems Group", ccy: "USD", amt: 53200, invDate: addDays(REF_DATE, -50), duo: 60, flow: [{ status: "Disputed", offset: 28 }] },
  ].forEach(function(tc) {
    var a = tc.amt, cd = r2(a * ADVANCE_RATE), hb = r2(r2(a) - cd);
    var dd = addDays(tc.invDate, tc.duo);
    var h = [{ status: "Received", date: tc.invDate }], st = "Received";
    tc.flow.forEach(function(step) { h.push({ status: step.status, date: addDays(tc.invDate, step.offset) }); st = step.status; });
    var tcDays = daysBetween(tc.invDate, dd);
    var ic = r2(cd * DAILY_RATE * tcDays);
    invoices.push({ id: tc.id, supplierName: SUPPLIER.name, buyerName: tc.buyer, amount: a, currency: tc.ccy, capitalDue: cd, holdback: hb, interestCharged: ic, deferredPayment: r2(hb - ic), daysToMaturity: tcDays, invoiceDate: tc.invDate, dueDate: dd, fundedDate: tc.invDate, createdDate: tc.invDate, fullyRepaidDate: null, invoiceStatus: st, invoiceStatusHistory: h, fundingStatus: "funded", partialApprovedAmount: 0 });
  });
  return { invoices: invoices, payments: rawPayments };
}

