    paysForInv.forEach(function(p) { if (p.source === "supplier_recourse" || p.kind === "holdback" || p.kind === "pass_through") dispSupplierPaid += p.amount || 0; if (p.source !== "supplier_recourse" && p.kind !== "holdback") totalBuyerPaid += p.amount || 0; });
