          totalBuyerPaid: r2(totalBuyerPaid),
          fundedRecoveryAmount: r2(settledFunded), passThroughAmount: r2(settledPassThrough),
          settlementKind: settledKind,
          cnDilutionApplied: r2(cnDilutionByInvoice.get(rawInv.id) || 0),
