  var prog = inv.fundingProgram ? FUNDING_PROGRAMS_DB.find(function(fp) { return fp.id === inv.fundingProgram; }) : null;
  var thD = (prog && prog.thresholdDeemed != null) ? prog.thresholdDeemed : 60;
  var aged = (inv.daysOverdue || 0) > thD;
