            var availableTypes = [];
            var _tSeen = {};
            entries.forEach(function(e) { if (!_tSeen[e.baseType]) { _tSeen[e.baseType] = true; availableTypes.push(e.baseType); } });
            availableTypes.sort();

            // Apply filters (search, type, direction, date range)
            var bsFiltered = entries.slice();
