                    <div style={{ fontSize: 17, fontWeight: 700, fontFamily: "'JetBrains Mono', monospace", color: calcAvail >= 0 ? "#10B981" : "#DC2626" }}>{money(r2(calcAvail), prog.currency)}</div>
