                  maxSize: String(p.maxSize || ""), maxAdvanceRate: String((p.maxAdvanceRate * 100).toFixed(0)),
                  minInterestRate: String((p.minInterestRate * 100).toFixed(1)),
                  maxInvoiceTerm: String(p.maxInvoiceTerm || ""),
